/// <summary>
/// This is an UIBuilder class for report CylinderDepositStatusReport.
/// </summary>
internal final class ETGCylinderDepositStatusReportUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGCylinderDepositStatusReportContract contract;
    DialogField dialogFromDate;
    DialogField dialogToDate;
    DialogField custAccount;
    DialogField deposit;
    DialogField invoiceId;
    DialogField size;


}

Method.Source:
public void build()
{
    contract            = this.dataContractObject() as ETGCylinderDepositStatusReportContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGCylinderDepositStatusReportContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGCylinderDepositStatusReportContract,parmToDate), contract);
    custAccount         = this.addDialogField(methodStr(ETGCylinderDepositStatusReportContract, parmCustAccount), contract);
    deposit             = this.addDialogField(methodStr(ETGCylinderDepositStatusReportContract,parmDeposit), contract);
    invoiceId           = this.addDialogField(methodStr(ETGCylinderDepositStatusReportContract, parmInvoiceId), contract);
    size                = this.addDialogField(methodStr(ETGCylinderDepositStatusReportContract, parmSize), contract);

}

public void postBuild()
{
    Dialog dialogobj    = this.dialog();

    super();
    dialogFromDate      = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGCylinderDepositStatusReportContract, parmFromDate));
    dialogToDate        = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGCylinderDepositStatusReportContract, parmToDate));
    custAccount         = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGCylinderDepositStatusReportContract, parmCustAccount));
    custAccount.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGCylinderDepositStatusReportUIBuilder, custAccountMultiSelectLookup), this);
    deposit             = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGCylinderDepositStatusReportContract, parmDeposit));
    invoiceId           = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGCylinderDepositStatusReportContract, parmInvoiceId));
    invoiceId.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGZeroRatedSalesReportUIBuilder, InvoiceIdMultiSelectLookup), this);
    size                = this.bindInfo().getDialogField(this.dataContractObject(),methodStr(ETGCylinderDepositStatusReportContract, parmSize));
    //   size.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGCylinderDepositStatusReportUIBuilder,lookupSize),this);

    if(custAccount)
    {
        custAccount.lookupButton(2);
    }
    if(invoiceId)
    {
        invoiceId.lookupButton(2);
    }

}

public void postRun()
{
    ETGCylinderDepositStatusReportContract etgCylinderDepositStatusReportContract = this.dataContractObject();
}

/// <summary>
/// Multiselect lookup for cust account parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void custAccountMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conCustTable;

    qbds = query.addDataSource(tableNum(CustTable));

    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(CustTable,AccountNum));

    qbds = qbds.addDataSource(tableNum(DirPartyTable));
    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(DirPartyTable,Name));
    qbds.relations(true);
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conCustTable);
}

/// <summary>
/// Multi select lookup for InvoiceId parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void InvoiceIdMultiSelectLookup(FormStringControl _control)
{
    Query  query = new Query();
    QueryBuildDataSource qbds;
    container conInvoiceId;
    qbds = query.addDataSource(tableNum(CustInvoiceJour));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceId));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, SalesId));
    qbds.addSelectionField(fieldNum(CustInvoiceJour, InvoiceAccount));
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conInvoiceId);
}
